import{_ as a,o as n,c as o,a3 as l}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"86. Uniform And Laundry Allowance","description":"","frontmatter":{"title":"86. Uniform And Laundry Allowance","eba":"Mental Health Services 2024-2028","topics":["allowances","wages"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/86-uniform-and-laundry-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/86-uniform-and-laundry-allowance.md"}'),t={name:"ebas/mental-health/rpn-pen-mho/allowances/86-uniform-and-laundry-allowance.md"};function r(s,e,i,d,h,p){return n(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="_86-uniform-and-laundry-allowance" tabindex="-1">86. Uniform And Laundry Allowance <a class="header-anchor" href="#_86-uniform-and-laundry-allowance" aria-label="Permalink to &quot;86. Uniform And Laundry Allowance&quot;">​</a></h1><p><strong>86.1</strong> Where an Employer requires an Employee to wear a particular type or style of uniform then the Employer shall provide this at no cost to the Employee. Payment in lieu of providing the uniform is not permitted.</p><p><strong>86.2</strong> Where a uniform is not provided by the Employer the Employee shall be paid a uniform allowance at daily or weekly rate set out <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>, whichever is the lesser amount in total.</p><p><strong>86.3</strong> Where laundering by or at the expense of the Employer is not provided, an Employee shall be paid a laundry allowance at the daily or weekly rate set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>, whichever is the lesser amount in total.</p><p><strong>86.4</strong> The uniform allowances but not the laundry allowance shall be paid to an Employee during all absences on leave, except absence on long service leave and absence on sick leave beyond 21 days. Where, prior to taking leave, an Employee was paid a uniform allowance other than at the weekly rate, the rate to be paid during absence on leave shall be the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>86.5</strong> Where an Employer provides an Employee with uniforms, all articles so provided remain the property of the Employer.</p><p><strong>86.6</strong> The rounding provision does not apply to the calculation of this allowance.</p>',7)])])}const u=a(t,[["render",r]]);export{m as __pageData,u as default};
